class Solution:
    def largeGroupPositions(self, s: str) -> List[List[int]]:
        res = []
        start = 0
        for end in range(1, len(s)):
            if s[end] != s[start]:
                if end - start >= 3:
                    res.append([start, end - 1])
                start = end
        if len(s) - start >= 3:
            res.append([start, len(s) - 1])
        return res
